--
-- Tabelstructuur voor tabel `data_breaches`
--

CREATE TABLE `data_breaches` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `breach_date` date NOT NULL,
  `discovery_date` date NOT NULL,
  `breach_type` enum('confidentiality','integrity','availability','mixed') NOT NULL,
  `personal_data_affected` text NOT NULL,
  `affected_data_subjects` int(11) DEFAULT NULL,
  `causes` text NOT NULL,
  `measures_taken` text NOT NULL,
  `notified_authority` enum('yes','no','in_progress') DEFAULT 'no',
  `notification_date` date DEFAULT NULL,
  `notified_affected_persons` enum('yes','no','in_progress') DEFAULT 'no',
  `risk_level` enum('low','medium','high') NOT NULL,
  `status` enum('open','investigating','contained','resolved','closed') DEFAULT 'open',
  `reported_by` int(11) NOT NULL,
  `assigned_to` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Tabelstructuur voor tabel `dpia_registrations`
--

CREATE TABLE `dpia_registrations` (
  `id` int(11) NOT NULL,
  `record_id` int(11) NOT NULL,
  `description` text DEFAULT NULL,
  `necessity_proportionality` text DEFAULT NULL,
  `mitigation_measures` text DEFAULT NULL,
  `residual_risk` text DEFAULT NULL,
  `overall_risk_level` enum('low','medium','high') DEFAULT 'medium',
  `status` enum('draft','in_progress','under_review','approved','rejected','implemented') NOT NULL DEFAULT 'draft',
  `registered_by` int(11) NOT NULL,
  `registered_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `notes` text DEFAULT NULL,
  `title` varchar(255) NOT NULL DEFAULT 'DPIA Assessment',
  `review_date` date DEFAULT NULL,
  `processing_activity_description` text DEFAULT NULL,
  `risk_origin` enum('new_technology','large_scale','sensitive_data','systematic_monitoring','combination_datasets','vulnerable_groups','other') DEFAULT 'other',
  `necessity_test` text DEFAULT NULL,
  `proportionality_test` text DEFAULT NULL,
  `data_subjects_affected` int(11) DEFAULT 0,
  `data_categories` text DEFAULT NULL,
  `compliance_checklist` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`compliance_checklist`)),
  `risk_assessment_matrix` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`risk_assessment_matrix`)),
  `consultation_conducted` enum('yes','no','planned') DEFAULT 'no',
  `consultation_details` text DEFAULT NULL,
  `recommendations` text DEFAULT NULL,
  `management_approval` enum('pending','approved','rejected','revised') DEFAULT 'pending',
  `approved_by` int(11) DEFAULT NULL,
  `approval_date` date DEFAULT NULL,
  `necessity` text DEFAULT NULL,
  `proportionality` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Gegevens worden geëxporteerd voor tabel `dpia_registrations`
--

INSERT INTO `dpia_registrations` (`id`, `record_id`, `description`, `necessity_proportionality`, `mitigation_measures`, `residual_risk`, `overall_risk_level`, `status`, `registered_by`, `registered_at`, `updated_at`, `notes`, `title`, `review_date`, `processing_activity_description`, `risk_origin`, `necessity_test`, `proportionality_test`, `data_subjects_affected`, `data_categories`, `compliance_checklist`, `risk_assessment_matrix`, `consultation_conducted`, `consultation_details`, `recommendations`, `management_approval`, `approved_by`, `approval_date`, `necessity`, `proportionality`) VALUES
(300000009, 1, 'DPIA voor de verwerking van klantgegevens ten behoeve van administratie, facturatie en betalingsherinneringen.', 'De verwerking is noodzakelijk voor de uitvoering van de overeenkomst met klanten. Er is geen minder ingrijpend alternatief voor het bijhouden van klantgegevens en facturatie.', 'Versleutelde klantendatabase, MFA op factuursoftware, toegangsbeheer, geheimhoudingsverklaringen, periodieke back-ups, functiescheiding.', 'Laag - resterend risico na implementatie van maatregelen is aanvaardbaar.', 'high', '', 100000006, '2024-01-01 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd door management. Restrisico aanvaardbaar.', 'DPIA - Klantadministratie en facturatie', '2025-06-01', 'Verwerking van klantgegevens voor offertes, werkbonnen, facturen en betalingsherinneringen.', 'large_scale', 'De verwerking is noodzakelijk voor de uitvoering van de overeenkomst (art. 6.1.b AVG) en de fiscale bewaarplicht (art. 6.1.c AVG).', 'Er worden alleen minimale persoonsgegevens verwerkt die noodzakelijk zijn voor facturatie. Bewaartermijn is wettelijk bepaald op 7 jaar.', 5000, 'NAW-gegevens, telefoonnummer, e-mailadres, factuuradres, klantnummer, betalingshistorie, offertes, werkbonnen', NULL, NULL, 'no', NULL, 'Periodieke review van toegangsrechten, jaarlijkse privacy awareness training voor administratief personeel.', 'approved', NULL, '2024-01-15', NULL, NULL),
(300000010, 2, 'DPIA voor het aansturen van monteurs, registreren van werkzaamheden en vastleggen van materialen en uren.', 'De verwerking is noodzakelijk voor de uitvoering van de overeenkomst en de logistieke aansturing van monteurs.', 'Werkbon-app met versleuteling, tablet met pincode, geen klantgegevens op privételefoons, privacy training monteurs, foto´s zonder gezichten.', 'Laag - maatregelen zoals versleuteling en training beperken risico´s voldoende.', 'high', '', 100000006, '2024-01-15 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Monteurs krijgen jaarlijkse privacy training.', 'DPIA - Werkbonnen en routeplanning voor monteurs', '2025-06-01', 'Aansturen van monteurs, registreren van werkzaamheden, vastleggen van materialen en uren met handtekening klant.', 'sensitive_data', 'Noodzakelijk voor uitvoering overeenkomst, routeplanning en kwaliteitsborging van dienstverlening.', 'Alleen noodzakelijke gegevens worden gedeeld met monteurs. Foto´s worden beperkt tot rioolproblemen, geen personen.', 5000, 'Klant: NAW, telefoon, afspraak tijd; Monteur: naam, locatie; Werk: omschrijving, foto´s, handtekening, materialen', NULL, NULL, 'no', NULL, 'Periodieke evaluatie van foto´s, uitbreiden encryptie naar alle mobiele devices, anonimiseren van handtekeningen waar mogelijk.', 'approved', NULL, '2024-01-30', NULL, NULL),
(300000011, 4, 'DPIA voor de verwerking van medewerkersgegevens, salaris, verlof, ziekteverzuim en beoordelingen.', 'De verwerking is noodzakelijk op basis van wettelijke verplichtingen (fiscaal, sociale zekerheid) en de arbeidsovereenkomst.', 'Versleutelde HR-software, MFA, aparte medische dossiers, verwerkersovereenkomst met salarisadministrateur, geheimhouding, toegangsbeheer.', 'Laag - BSN en medische gegevens zijn extra beschermd via strikte toegangscontrole.', 'high', '', 100000006, '2024-01-10 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Medische gegevens voldoen aan extra beschermingsniveau.', 'DPIA - Personeelsadministratie en salarisverwerking', '2025-06-01', 'Administratie van medewerkers, salaris, verlof, ziekteverzuim, beoordelingen.', 'sensitive_data', 'Wettelijke verplichting op grond van belastingwetgeving, sociale zekerheid en Arbowet.', 'Medische gegevens worden strikt gescheiden van reguliere personeelsdossiers. Alleen HR heeft toegang tot BSN.', 210, 'NAW, BSN, geboortedatum, bankrekening, contract, salaris, verlofdagen, ziekteverzuim (medisch), beoordelingen', NULL, NULL, 'no', NULL, 'Periodieke audit van toegangsrechten, jaarlijkse AVG-training voor HR-medewerkers.', 'approved', NULL, '2024-01-20', NULL, NULL),
(300000012, 5, 'DPIA voor het behandelen van sollicitaties, plannen van gesprekken en aannameprocedure.', 'Verwerking is gebaseerd op toestemming van sollicitant en precontractuele maatregelen.', 'Beveiligde sollicitatiemail, CV´s in aparte map met wachtwoord, selectiecommissie van minimaal 2 personen, verwijderingsprocedure.', 'Laag - duidelijke bewaartermijnen en verwijderingsprocedure minimaliseren risico´s.', 'medium', '', 100000006, '2024-02-01 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Verwerkingsactiviteit voldoet aan AVG-eisen.', 'DPIA - Werving en selectie van personeel', '2025-06-01', 'Behandelen van sollicitaties, plannen van gesprekken, aannameprocedure.', 'vulnerable_groups', 'Noodzakelijk voor werving en selectie van geschikt personeel. Sollicitanten worden geïnformeerd over verwerking.', 'CV´s worden niet langer bewaard dan noodzakelijk. Alleen relevante informatie wordt gebruikt voor selectie.', 150, 'NAW, CV, motivatiebrief, diploma´s, VOG, referenties, gespreksverslagen', NULL, NULL, 'no', NULL, 'Standaard bewaartermijn van 4 weken hanteren, tenzij expliciete toestemming voor langere bewaartermijn.', 'approved', NULL, '2024-02-15', NULL, NULL),
(300000013, 7, 'DPIA voor het versturen van nieuwsbrieven via Mailchimp (VS) met internationale doorgifte van persoonsgegevens.', 'Verwerking is gebaseerd op toestemming van abonnees (double opt-in).', 'Double opt-in, TLS versleuteling, anonimisering IP-adressen, afmeldlink in elke mail, SCC´s voor VS-partijen, voorkeur voor EU-hosting.', 'Midden - internationale doorgifte naar VS brengt risico´s met zich mee, maar SCC´s bieden voldoende waarborgen.', 'medium', '', 100000006, '2024-02-15 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. SCC´s zijn getekend met Mailchimp.', 'DPIA - Nieuwsbrieven met internationale doorgifte', '2025-06-01', 'Informeren over acties, onderhoudstips, nieuwe diensten via e-mailnieuwsbrieven.', 'other', 'Verwerking is gebaseerd op expliciete toestemming. Abonnees kunnen zich altijd afmelden.', 'Alleen e-mailadres en voornaam worden verwerkt. Geen gevoelige gegevens.', 2500, 'E-mailadres, naam, aanmelddatum, openingsgedrag, IP-adres', NULL, NULL, 'no', NULL, 'Overwegen om over te stappen naar EU-gebaseerde nieuwsbriefdienst (bijv. Sendinblue) om internationale doorgifte te voorkomen.', 'approved', NULL, '2024-03-01', NULL, NULL),
(300000014, 16, 'DPIA voor het gebruik van Microsoft 365 voor e-mail, bestandsopslag, samenwerking en agenda met internationale doorgifte naar VS.', 'Verwerking is gebaseerd op gerechtvaardigd belang voor efficiënte bedrijfsvoering.', 'MFA verplicht voor alle accounts, versleuteling in rust en transit, EU Data Boundary, audit logging, retention policies, SCC´s, Data Processing Agreement.', 'Laag - Microsoft EU Data Boundary houdt data binnen EU, SCC´s bieden juridische waarborgen.', 'high', '', 100000006, '2024-01-01 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Data blijft binnen EU dankzij EU Data Boundary.', 'DPIA - Microsoft 365 zakelijke e-mail en cloudopslag', '2025-06-01', 'Dagelijkse bedrijfsvoering: e-mail communicatie, opslag van documenten, Teams vergaderingen.', 'large_scale', 'Noodzakelijk voor dagelijkse bedrijfsvoering. Geen adequaat alternatief met vergelijkbare functionaliteit in EU.', 'Gevoelige documenten worden versleuteld. Toegangsrechten zijn strikt gereguleerd.', 250, 'E-mailadressen, namen, inhoud e-mails, documenten met persoonsgegevens, metadata, IP-adressen', NULL, NULL, 'no', NULL, 'Gebruik maken van Microsoft EU Data Boundary. Periodieke review van data locatie.', 'approved', NULL, '2024-01-20', NULL, NULL),
(300000015, 19, 'DPIA voor het maken van back-ups van alle systemen naar een externe, veilige locatie voor disaster recovery.', 'Verwerking is gebaseerd op gerechtvaardigd belang voor business continuity en data recovery.', 'End-to-end encryptie van back-ups (client-side), versleutelde overdracht, MFA voor back-upconsole, verwerkersovereenkomst, regelmatige restore-test.', 'Laag - end-to-end encryptie zorgt dat back-up provider geen toegang heeft tot data.', 'high', '', 100000006, '2024-01-15 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. End-to-end encryptie is geïmplementeerd.', 'DPIA - Cloud back-ups naar externe locatie', '2025-06-01', 'Back-ups maken van klantendatabase, facturen, werkbonnen, e-mail voor disaster recovery.', 'other', 'Noodzakelijk voor continuïteit van dienstverlening en bescherming tegen dataverlies.', 'Alle back-ups zijn end-to-end versleuteld. Encryptiesleutels worden lokaal bewaard.', 7500, 'Alle persoonsgegevens (klanten, medewerkers, leveranciers) in back-ups', NULL, NULL, 'no', NULL, 'Maandelijks testen van restore-procedure. Encryptiesleutels veilig en gescheiden opslaan.', 'approved', NULL, '2024-01-30', NULL, NULL),
(300000016, 8, 'DPIA voor het beheren van sociale media kanalen met internationale doorgifte naar Meta (VS).', 'Verwerking is gebaseerd op gerechtvaardigd belang voor marketing en communicatie.', 'Privacy-instellingen maximaal, geen custom audiences zonder consent, anonieme statistieken, SCC´s, Page Insights joint controllership met Meta.', 'Midden - joint controllership met Meta vereist extra aandacht, maar SCC´s bieden waarborgen.', 'medium', '', 100000006, '2024-02-20 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Page Insights addendum is geaccepteerd.', 'DPIA - Social media kanalen (Facebook, Instagram, LinkedIn)', '2025-06-01', 'Plaatsen van berichten, reageren op klanten, inzicht in bereik en doelgroep.', 'other', 'Noodzakelijk voor marketing, klantcommunicatie en merkbekendheid.', 'Alleen openbare informatie wordt verwerkt. Geen gevoelige gegevens.', 10000, 'Openbare profielinformatie, statistieken, cookies/pixels', NULL, NULL, 'no', NULL, 'Periodiek herzien van joint controllership verklaring met Meta. Overwegen van EU-alternatieven.', 'approved', NULL, '2024-03-05', NULL, NULL),
(300000017, 30, 'DPIA voor geïntegreerde software voor offertes, werkbonnen, routeplanning, facturatie en klantenbeheer.', 'Verwerking is noodzakelijk voor de uitvoering van de overeenkomst met klanten.', 'Software met MFA, versleutelde database, logging, backups, alleen toegankelijk via VPN, verwerkersovereenkomst met softwareleverancier.', 'Laag - versleuteling en toegangsbeheer beperken risico´s voldoende.', 'high', '', 100000006, '2024-01-20 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Softwareleverancier heeft ISO 27001 certificering.', 'DPIA - Branchesoftware voor rioolreiniging', '2025-06-01', 'Geïntegreerde software voor offertes, werkbonnen, routeplanning, facturatie, klantenbeheer.', 'large_scale', 'Noodzakelijk voor efficiënte bedrijfsvoering en klantbeheer. Geen geschikt alternatief.', 'Alleen geautoriseerde gebruikers hebben toegang. Alle toegang wordt gelogd.', 5000, 'Alle klantgegevens, werkbonnen, foto´s, handtekeningen, facturen, betalingshistorie', NULL, NULL, 'no', NULL, 'Periodieke security audit van de branchesoftware. Tweejaarlijkse penetration test.', 'approved', NULL, '2024-02-05', NULL, NULL),
(300000018, 11, 'DPIA voor het analyseren van websitebezoekersgedrag via Google Analytics met internationale doorgifte naar VS.', 'Verwerking is gebaseerd op toestemming via cookiebanner (opt-in).', 'IP-anonimisering, cookiemelding met opt-in, data sharing uitzetten, Do Not Track respecteren, SCC´s, overwegen van EU-alternatieven.', 'Midden - internationale doorgifte naar VS, maar SCC´s en anonimisering beperken risico´s.', 'medium', '', 100000006, '2024-01-20 09:00:00', '2026-05-17 08:23:01', 'DPIA goedgekeurd. Overstap naar Matomo wordt voorbereid.', 'DPIA - Google Analytics website statistieken', '2025-06-01', 'Inzicht in bezoekersaantallen, populaire pagina´s, conversies voor website-optimalisatie.', 'new_technology', 'Verwerking is gebaseerd op expliciete toestemming via cookiebanner.', 'IP-adressen worden geanonimiseerd. Geen cross-device tracking zonder toestemming.', 25000, 'IP-adres (geanonimiseerd), cookie-ID, bezochte pagina´s, tijd op site, apparaattype', NULL, NULL, 'no', NULL, 'Overstappen naar privacy-first analytics zoals Matomo of Plausible (EU-gehost).', 'approved', NULL, '2024-02-05', NULL, NULL);

