INSERT INTO `gdpr_register` (`id`, `has_processing_agreement_with_third_party`, `we_are_processor`, `processing_activity`, `name_data_controller`, `contact_data_controller`, `name_joint_data_controller`, `contact_joint_data_controller`, `name_representative`, `contact_representative`, `name_dpo`, `contact_dpo`, `purpose_of_processing`, `legal_basis`, `categories_personal_data`, `categories_data_subjects`, `categories_recipients`, `retention_periods`, `risk_level`, `technical_measures`, `organizational_measures`, `dpia_required`, `is_international_data_transfers`, `to_country`, `safeguards`, `created_at`, `updated_at`, `review_due_date`, `created_by`, `updated_by`, `department`, `status`, `legitimate_interest_description`, `dpia_status`) VALUES
(1, 'Yes', 'No', 'Klantadministratie en facturatie', 'Teeuwissen Rioolreiniging Huizen', 'info@teeuwissen-riool.nl', NULL, NULL, NULL, NULL, 'Dhr. J. Teeuwissen', 'info@teeuwissen-riool.nl', 'Administratie van klantgegevens voor offertes, werkbonnen, facturen en betalingsherinneringen', 'contract', 'NAW-gegevens, telefoonnummer, e-mailadres, factuuradres, klantnummer, betalingshistorie, offertes, werkbonnen', 'Particulieren, bedrijven, gemeenten, woningcorporaties, VvE\'s', 'Boekhouder, factuursoftware, incassobureau (bij wanbetaling)', '7 jaar (fiscale bewaarplicht), offertes 1 jaar indien niet geaccepteerd', 'high', 'Versleutelde klantendatabase (Excel/CRM), beveiligde factuursoftware (MFA), papier in afgesloten kast', 'Geheimhoudingsverklaring medewerkers, toegangsbeheer, backups versleuteld, functiescheiding', 'yes', 'no', '', 'N.v.t.', '2023-12-31 23:00:00', '2025-06-14 22:00:00', '2025-06-01', NULL, NULL, '', 'active', NULL, 'completed'),
(2, 'Yes', 'No', 'Werkbonnen en routeplanning voor monteurs', 'Teeuwissen Rioolreiniging Huizen', 'info@teeuwissen-riool.nl', NULL, NULL, NULL, NULL, 'Dhr. J. Teeuwissen', 'info@teeuwissen-riool.nl', 'Aansturen van monteurs, registreren van werkzaamheden, vastleggen van materialen en uren', 'contract', 'Klant: NAW, telefoon, afspraak tijd; Monteur: naam, locatie; Werk: omschrijving, foto\'s (optioneel), handtekening klant, materialen', 'Klanten, monteurs, eventueel derden (verhuurder bij huurwoning)', 'Monteurs (tablet/telefoon), planner, administratie', '2 jaar na afronding werk (aansprakelijkheid), foto\'s riool 6 maanden', 'high', 'Werkbon-app met versleuteling, tablet met pincode, geen klantgegevens op privételefoons, foto\'s zonder gezichten', 'Privacy training monteurs, geen foto\'s van binnen woning, handtekening klant op papier (niet digitaal delen)', 'yes', 'no', '', 'N.v.t.', '2023-12-31 23:00:00', '2025-06-11 22:00:00', '2025-06-01', NULL, NULL, '', 'active', NULL, 'completed'),
